import 'package:flutter/material.dart';import 'package:get/get.dart';import '../../common/app_button.dart';import '../../common/app_card.dart';import '../../common/app_motion.dart';import '../../common/loading_state.dart';import '../../common/responsive.dart';import '../../controllers/gamification_controller.dart';
class GamificationView extends StatefulWidget{const GamificationView({super.key});@override State<GamificationView> createState()=>_GamificationViewState();}class _GamificationViewState extends State<GamificationView>{@override void initState(){super.initState();WidgetsBinding.instance.addPostFrameCallback((_){if(mounted)Get.find<GamificationController>().load();});}@override Widget build(BuildContext context){final c=Get.find<GamificationController>();return Scaffold(appBar:AppBar(title:const Text('Quests')),body:PageShell(child:Obx(()=>c.loading.value?const LoadingState():GameListView(children:[AppCard(child:ListTile(leading:const Icon(Icons.local_fire_department_rounded),title:Text('${c.streak.value.currentStreak} day streak'),subtitle:Text('${c.streak.value.missedDays} missed days'))),AppButton(label:'Check palm refill',icon:Icons.favorite_rounded,onPressed:c.refillPalm),const SizedBox(height:12),Text('Daily quests',style:Theme.of(context).textTheme.titleLarge),...c.quests.map((q)=>AppCard(child:ListTile(title:Text(q.challengeId),subtitle:LinearProgressIndicator(value:q.required==0?1:(q.current/q.required).clamp(0,1)),trailing:Text(q.status)))),const SizedBox(height:12),Text('Achievements',style:Theme.of(context).textTheme.titleLarge),...c.achievements.map((a)=>AppCard(child:ListTile(leading:Icon(a.achieved?Icons.check_circle:Icons.radio_button_unchecked),title:Text(a.achievementTitle),subtitle:Text(a.title))))]))));}}
